SELECT category, product_id, revenue FROM (
  SELECT p.category AS category, s.product_id, SUM(s.amount) AS revenue,
    RANK() OVER (PARTITION BY p.category ORDER BY SUM(s.amount) DESC) AS rk
  FROM sales s JOIN products p ON s.product_id = p.product_id
  GROUP BY p.category, s.product_id
) t WHERE rk <= 5;

